func Test_EmbedAsync(t *testing.T) {
	// Standalone embedding via async API path with balanced preset
	var texts []string
	if err := json.Unmarshal([]byte(`["Async embedding test"]`), &texts); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	var config kreuzberg.ExtractionConfig
	if err := json.Unmarshal([]byte(`{"model":{"name":"balanced","type":"preset"},"normalize":true}`), &config); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	result, err := kreuzberg.EmbedTexts(texts, config)
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
	assert.Equal(t, len(result.Embeddings), 1, "expected exactly 1 elements")
	if result.EmbeddingDimensions != 768 {
		t.Errorf("equals mismatch: got %v", result.EmbeddingDimensions)
	}
	assert.True(t, result.EmbeddingsValid, "expected true")
	assert.True(t, result.EmbeddingsFinite, "expected true")
	assert.True(t, result.EmbeddingsNonZero, "expected true")
}

